"""
Task 058 – individuals.csv
Generate a CSV counting persons whose best-fit model-rule combination
aligns with each model × rule pair from the indiv_table predictions.

Strategy (round 3):
  - Load each model CSV: columns are syllogism tasks, rows are predicted responses.
  - Load each rule script as a function that post-processes a model's predictions.
  - Load participant data from Ragni2016.csv.
  - For each participant × each model × each rule, compute the number of
    matching responses (model+rule prediction vs participant response).
  - Assign each participant to their best-fitting model-rule combination
    (break ties by first encountered, consistent with typical ccobra approach).
  - Count participants per model-rule combo and write individuals.csv.
"""

import os
import sys
import importlib.util
import pandas as pd
import numpy as np

# ── paths ────────────────────────────────────────────────────────────────────
BASE = "benchmark/datasets/nvc"
MODELS_DIR = os.path.join(BASE, "scripts", "indiv_table", "models")
RULES_DIR  = os.path.join(BASE, "scripts", "indiv_table", "rules")
DATA_PATH  = os.path.join(BASE, "Ragni2016.csv")
OUT_DIR    = "pred_results"
OUT_PATH   = os.path.join(OUT_DIR, "individuals.csv")

os.makedirs(OUT_DIR, exist_ok=True)

# ── helper: load a rule module and return its apply / predict function ────────
def load_rule_module(rule_path):
    """Load a rule .py file; return the module object."""
    spec = importlib.util.spec_from_file_location("rule_mod", rule_path)
    mod  = importlib.util.module_from_spec(spec)
    spec.loader.exec_module(mod)
    return mod

# ── load participant data ─────────────────────────────────────────────────────
data = pd.read_csv(DATA_PATH)

# Parse syllogism task into a canonical key: "Q1;A;B/Q2;C;A" form
# The task column has format "Quant;term1;term2/Quant;term2;term3"
# The response column has the participant's chosen conclusion.

# Build per-participant response dict: {task_key -> response}
# Each participant (id) answered a sequence of syllogisms (sequence column).
participants = data["id"].unique()

# ── load model CSVs ───────────────────────────────────────────────────────────
model_files = [f for f in os.listdir(MODELS_DIR) if f.endswith(".csv")]
model_names = [os.path.splitext(f)[0] for f in model_files]

# Each model CSV: rows = tasks, columns may vary.
# We expect: a task identifier column + prediction columns.
# Inspect first file to understand structure.
def load_model_csv(path):
    df = pd.read_csv(path)
    return df

model_dfs = {}
for fname, mname in zip(model_files, model_names):
    model_dfs[mname] = load_model_csv(os.path.join(MODELS_DIR, fname))

# ── load rule modules ─────────────────────────────────────────────────────────
rule_files = [f for f in os.listdir(RULES_DIR)
              if f.endswith(".py") and f != "__init__.py"]
rule_names = [os.path.splitext(f)[0] for f in rule_files]

rule_mods = {}
for fname, rname in zip(rule_files, rule_names):
    try:
        rule_mods[rname] = load_rule_module(os.path.join(RULES_DIR, fname))
    except Exception:
        rule_mods[rname] = None

# ── understand model CSV structure ───────────────────────────────────────────
# Print column names of first model for debugging
first_model = list(model_dfs.values())[0]

# Typical ccobra indiv_table model CSV structure:
# Columns: task (syllogism) | prediction (NVC / quantifier;terms or similar)
# OR:      syl | pred
# We need to map tasks to predictions.

def get_model_predictions(model_df):
    """
    Return a dict: {task_str -> prediction_str}.
    Try common column name patterns.
    """
    cols = list(model_df.columns)
    # Identify task column and prediction column
    task_col = None
    pred_col = None
    for c in cols:
        cl = c.lower().strip()
        if cl in ("task", "syllogism", "syl", "problem"):
            task_col = c
        if cl in ("prediction", "pred", "response", "conclusion"):
            pred_col = c
    # Fallback: assume first col = task, second = prediction
    if task_col is None:
        task_col = cols[0]
    if pred_col is None and len(cols) > 1:
        pred_col = cols[1]
    if pred_col is None:
        return {}
    result = {}
    for _, row in model_df.iterrows():
        result[str(row[task_col]).strip()] = str(row[pred_col]).strip()
    return result

model_preds = {mname: get_model_predictions(df) for mname, df in model_dfs.items()}

# ── understand rule application ───────────────────────────────────────────────
# Rules typically expose a function apply(prediction, syllogism) -> modified_prediction
# OR predict(syllogism, model_pred) -> prediction
# We try several common patterns.

def apply_rule(rule_mod, model_pred, task_str):
    """Apply a rule module to a model prediction. Return adjusted prediction."""
    if rule_mod is None:
        return model_pred
    # Try common function names
    for fn_name in ("apply", "predict", "transform", "adjust"):
        fn = getattr(rule_mod, fn_name, None)
        if fn is not None:
            try:
                return str(fn(model_pred, task_str)).strip()
            except Exception:
                try:
                    return str(fn(task_str, model_pred)).strip()
                except Exception:
                    pass
    # If no function found, return model prediction unchanged
    return model_pred

# ── compute best-fit model-rule per participant ───────────────────────────────
# For each participant, get their responses, then score each (model, rule) combo.

# Build participant response map: pid -> {task -> response}
participant_responses = {}
for pid, grp in data.groupby("id"):
    resp_map = {}
    for _, row in grp.iterrows():
        task_key = str(row["task"]).strip()
        resp_map[task_key] = str(row["response"]).strip()
    participant_responses[pid] = resp_map

# Get the set of all tasks
all_tasks = set()
for resp_map in participant_responses.values():
    all_tasks.update(resp_map.keys())

# Precompute rule-adjusted predictions for each model × rule × task
# Shape: {model: {rule: {task: adjusted_pred}}}
adjusted = {}
for mname, preds in model_preds.items():
    adjusted[mname] = {}
    for rname, rmod in rule_mods.items():
        task_preds = {}
        for task, mpred in preds.items():
            task_preds[task] = apply_rule(rmod, mpred, task)
        # Also add tasks present in participant data but missing in model
        for task in all_tasks:
            if task not in task_preds:
                task_preds[task] = apply_rule(rmod, "NVC", task)
        adjusted[mname][rname] = task_preds

# Score each participant against each (model, rule) combo
combo_keys   = [(m, r) for m in model_names for r in rule_names]
best_fit_counts = {(m, r): 0 for m, r in combo_keys}

for pid, resp_map in participant_responses.items():
    best_score = -1
    best_combo = combo_keys[0]
    for m, r in combo_keys:
        score = 0
        for task, actual in resp_map.items():
            predicted = adjusted[m][r].get(task, "NVC")
            if predicted == actual:
                score += 1
        if score > best_score:
            best_score = score
            best_combo = (m, r)
    best_fit_counts[best_combo] += 1

# ── write output CSV ──────────────────────────────────────────────────────────
rows = []
for m, r in combo_keys:
    rows.append({
        "Model": m,
        "Rule": r,
        "Num persons": best_fit_counts[(m, r)]
    })

out_df = pd.DataFrame(rows, columns=["Model", "Rule", "Num persons"])
# Format as "Model; Rule; Num persons" per row  — write with sep='; '
out_df.to_csv(OUT_PATH, index=False, sep=";")

print(f"Saved {OUT_PATH} with {len(out_df)} rows.")
